import React, { useState, useRef, useEffect } from 'react';
import { motion as Motion, AnimatePresence, useScroll, useMotionValueEvent } from 'framer-motion';
import { ShoppingBag, Search, Menu, X, User, Zap, Sparkles, Orbit, Command } from 'lucide-react';
import { NavLink, Link } from 'react-router-dom';
import { clsx } from 'clsx';
import { twMerge } from 'tailwind-merge';

function cn(...inputs) {
  return twMerge(clsx(inputs));
}

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchRef = useRef(null);
  const { scrollY } = useScroll();

  useMotionValueEvent(scrollY, "change", (latest) => {
    setIsScrolled(latest > 50);
  });

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (searchRef.current && !searchRef.current.contains(e.target)) {
        setIsSearchOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const navItems = [
    { name: 'Home', path: '/', icon: <Zap size={16} /> },
    { name: 'Store', path: '/store', icon: <ShoppingBag size={16} /> },
    { name: 'Drops', path: '/drops', icon: <Orbit size={16} /> },
  ];

  return (
    <div className="fixed top-6 inset-x-0 z-[100] flex justify-center px-4 pointer-events-none">
      <Motion.nav
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.8, ease: [0.23, 1, 0.32, 1] }}
        className={cn(
          "flex items-center justify-between py-2 px-3 md:px-6 rounded-full pointer-events-auto transition-all duration-500 ease-in-out",
          "bg-black/40 backdrop-blur-2xl border border-white/10 shadow-[0_0_40px_rgba(0,0,0,0.5)]",
          isScrolled ? "w-full max-w-2xl" : "w-full max-w-5xl"
        )}
      >
        <Link to="/" className="flex items-center gap-2 cursor-pointer group shrink-0">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center group-hover:shadow-[0_0_20px_rgba(99,102,241,0.6)] transition-all">
            <Sparkles size={18} className="text-white" />
          </div>
          <span className="text-xl font-black tracking-tighter text-white">NEO.</span>
        </Link>

        {!isSearchOpen && (
          <Motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }}
            className="hidden md:flex items-center gap-1 p-1 bg-white/5 rounded-full border border-white/5"
          >
            {navItems.map((item) => (
              <NavLink
                key={item.name}
                to={item.path}
                className={({ isActive }) => cn(
                  "relative px-5 py-2 text-xs font-bold transition-all rounded-full flex items-center gap-2 uppercase tracking-widest",
                  isActive ? "text-white" : "text-gray-500 hover:text-gray-300"
                )}
              >
                {({ isActive }) => (
                  <>
                    {isActive && (
                      <Motion.div
                        layoutId="nav-glow"
                        className="absolute inset-0 bg-gradient-to-r from-indigo-600 to-purple-600 rounded-full shadow-[0_0_15px_rgba(99,102,241,0.4)]"
                        transition={{ type: "spring", bounce: 0.3, duration: 0.6 }}
                      />
                    )}
                    <span className="relative z-10 flex items-center gap-2">
                      {item.icon} {item.name}
                    </span>
                  </>
                )}
              </NavLink>
            ))}
          </Motion.div>
        )}

        <div className="flex items-center gap-2">
          <Motion.div 
            ref={searchRef}
            animate={{ width: isSearchOpen ? (isScrolled ? '240px' : '320px') : '130px' }}
            className={cn(
              "hidden lg:flex items-center bg-white/5 rounded-full px-3 py-2 border transition-all duration-300 relative",
              isSearchOpen ? "border-indigo-500/50 bg-white/10" : "border-white/5 hover:border-white/20"
            )}
          >
            <Search 
              size={16} 
              className={cn("transition-colors", isSearchOpen ? "text-indigo-400" : "text-gray-500")} 
            />
            <input
              type="text"
              placeholder="Search..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              onFocus={() => setIsSearchOpen(true)}
              className="bg-transparent border-none outline-none text-xs text-white ml-2 w-full placeholder:text-gray-600"
            />
            <AnimatePresence>
              {!isSearchOpen ? (
                <Motion.div 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                  className="flex gap-1 absolute right-3 pointer-events-none"
                >
                  <span className="px-1.5 py-0.5 bg-white/10 rounded text-[9px] text-gray-400 font-mono border border-white/5 flex items-center gap-0.5">
                    <Command size={8} />K
                  </span>
                </Motion.div>
              ) : (
                searchQuery && (
                  <Motion.button
                    initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}
                    onClick={() => setSearchQuery("")}
                    className="absolute right-3 text-gray-400 hover:text-white"
                  >
                    <X size={14} />
                  </Motion.button>
                )
              )}
            </AnimatePresence>
          </Motion.div>
          <div className="flex items-center gap-2">
            <NavIcon icon={<User size={18} />} />
            <NavIcon icon={<ShoppingBag size={18} />} badge={3} />
            <button 
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)} 
              className="md:hidden p-2 text-white hover:bg-white/10 rounded-full transition-colors"
            >
              {isMobileMenuOpen ? <X size={22} /> : <Menu size={22} />}
            </button>
          </div>
        </div>
      </Motion.nav>
      <AnimatePresence>
        {isMobileMenuOpen && (
          <Motion.div
            initial={{ opacity: 0, y: -20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -20, scale: 0.95 }}
            className="fixed top-24 inset-x-4 p-8 bg-black/95 backdrop-blur-3xl border border-white/10 rounded-[2.5rem] flex flex-col gap-6 md:hidden shadow-2xl pointer-events-auto"
          >
             <div className="relative flex items-center bg-white/5 rounded-2xl p-4 border border-white/10">
                <Search size={20} className="text-gray-400" />
                <input type="text" placeholder="Search Store" className="bg-transparent border-none outline-none text-white ml-3 w-full" />
             </div>
             {navItems.map((item) => (
               <NavLink 
                key={item.name} 
                to={item.path} 
                onClick={() => setIsMobileMenuOpen(false)}
                className="text-4xl font-black text-white tracking-tighter hover:text-indigo-500 transition-colors"
               >
                {item.name}
               </NavLink>
             ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

const NavIcon = ({ icon, badge }) => (
  <Motion.button
    whileHover={{ scale: 1.1, y: -2 }}
    whileTap={{ scale: 0.95 }}
    className="relative p-2.5 text-white bg-white/5 rounded-full border border-white/5 hover:bg-white/10 transition-colors"
  >
    {icon}
    {badge && (
      <span className="absolute -top-1 -right-1 w-4 h-4 bg-indigo-600 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 border-black">
        {badge}
      </span>
    )}
  </Motion.button>
);

export default Navbar;

import React from 'react';
import { motion as Motion, useScroll, useTransform, useMotionValue, useSpring } from 'framer-motion';
import { ArrowUpRight, Play, ShieldCheck, Zap } from 'lucide-react';

const Hero = () => {
  const { scrollY } = useScroll();
  const yText = useTransform(scrollY, [0, 500], [0, 200]);

  const x = useMotionValue(0);
  const y = useMotionValue(0);
  const mouseX = useSpring(x, { stiffness: 150, damping: 20 });
  const mouseY = useSpring(y, { stiffness: 150, damping: 20 });

  const rotateX = useTransform(mouseY, [-300, 300], [10, -10]);
  const rotateY = useTransform(mouseX, [-300, 300], [-10, 10]);

  function handleMouseMove(event) {
    const rect = event.currentTarget.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    x.set(event.clientX - centerX);
    y.set(event.clientY - centerY);
  }

  return (
    <section 
      onMouseMove={handleMouseMove}
      className="relative min-h-screen w-full flex items-center justify-center perspective-1000 overflow-hidden pt-20"
    >
      <Motion.div 
        style={{ y: yText }}
        className="absolute top-1/4 left-0 w-full text-center pointer-events-none opacity-[0.03]"
      >
        <h1 className="text-[30vw] font-black tracking-tighter leading-none">NEO26</h1>
      </Motion.div>

      <div className="max-w-7xl mx-auto w-full px-6 grid grid-cols-12 items-center z-10">
        <div className="col-span-12 lg:col-span-6 space-y-12">
          <Motion.div 
            initial={{ opacity: 0, x: -30 }} 
            animate={{ opacity: 1, x: 0 }}
            className="inline-flex items-center gap-3 px-4 py-2 rounded-full bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 text-xs font-mono tracking-widest uppercase"
          >
            <Zap size={14} fill="currentColor" className="animate-pulse" />
            Stock Limited: Winter Phase 01
          </Motion.div>

          <Motion.h1 
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            className="text-7xl md:text-9xl font-black text-white leading-[0.8] tracking-tighter"
          >
            BEYOND <br /> <span className="text-indigo-600 italic">FABRIC.</span>
          </Motion.h1>

          <p className="text-gray-400 text-xl max-w-md font-light leading-relaxed">
            Engineered silhouettes for the high-performance lifestyle. 
            Integrated with <span className="text-white font-medium italic">Graphene-Lite</span> tech.
          </p>

          <div className="flex flex-wrap gap-6">
            <Motion.button 
              whileHover={{ scale: 1.05, boxShadow: "0 0 30px rgba(99,102,241,0.4)" }}
              className="px-12 py-6 bg-indigo-600 text-white rounded-2xl font-black flex items-center gap-3 group"
            >
              SHOP NOW <ArrowUpRight className="group-hover:rotate-45 transition-transform" />
            </Motion.button>
            <button className="flex items-center gap-4 text-white group">
              <div className="w-16 h-16 rounded-full border border-white/10 flex items-center justify-center group-hover:bg-white group-hover:text-black transition-all">
                <Play fill="currentColor" size={20} />
              </div>
              <span className="font-bold tracking-widest text-xs uppercase">View Film</span>
            </button>
          </div>
        </div>

        <Motion.div 
          style={{ rotateX, rotateY }}
          className="col-span-12 lg:col-span-6 relative flex justify-center mt-20 lg:mt-0 preserve-3d"
        >
          <div className="relative w-full max-w-[500px] aspect-[4/5] rounded-[3.5rem] overflow-hidden border border-white/10 shadow-2xl">
            <img 
              src="https://images.unsplash.com/photo-1539109136881-3be0616acf4b?q=80&w=800" 
              className="w-full h-full object-cover grayscale hover:grayscale-0 transition-all duration-1000 scale-110" 
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-60" />
          </div>

          <Motion.div 
            style={{ translateZ: 50 }}
            className="absolute -top-10 -right-4 md:-right-10 p-8 bg-black/60 backdrop-blur-xl rounded-3xl border border-white/10 shadow-2xl space-y-4"
          >
            <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center"><ShieldCheck className="text-white" /></div>
            <div>
              <p className="text-[10px] font-mono text-gray-500 uppercase tracking-widest">Protection</p>
              <p className="text-lg font-black text-white leading-none">LEVEL 04</p>
            </div>
          </Motion.div>
        </Motion.div>
      </div>
    </div>
  );
};

export default Hero;
